package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.MockedStatic;

class CSVParserParseFileTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);
    }

    @Test
    void parse_fileNullFile_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((File) null, charset, format));
        assertEquals("file", ex.getMessage());
    }

    @Test
    void parse_fileNullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockFile, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_fileInvokesInputStreamReaderAndReturnsCSVParser() throws IOException {
        try (MockedConstruction<FileInputStream> mockedFis = mockConstruction(FileInputStream.class);
             MockedConstruction<InputStreamReader> mockedIsr = mockConstruction(InputStreamReader.class);
             MockedStatic<Assertions> mockedAssertions = mockStatic(Assertions.class)) {

            // Arrange: Assertions.notNull does nothing here
            mockedAssertions.when(() -> Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            // Act
            CSVParser parser = CSVParser.parse(mockFile, charset, format);

            // Assert
            assertNotNull(parser);
            // The returned parser is constructed with InputStreamReader and format, check format field is set
            assertEquals(format, parser.getHeaderMap() == null ? null : parser.format);
            // verify Assertions.notNull called twice
            mockedAssertions.verify(() -> Assertions.notNull(mockFile, "file"));
            mockedAssertions.verify(() -> Assertions.notNull(format, "format"));
        }
    }
}
